// NEWS2 — National Early Warning Score 2 (RCP 2017)
const j   = $input.first().json;
const inp = (j.input && typeof j.input === 'object') ? j.input : j;

let score = 0;
const notes = [];
const rr   = parseFloat(inp.rr);
const spo2 = parseFloat(String(inp.spo2 || '').replace('%',''));
const sbp  = parseFloat(String(inp.sbp  || '').split('/')[0]);
const hr   = parseFloat(inp.hr);
const temp = parseFloat(inp.temp);
const gcs  = inp.gcs != null ? parseFloat(inp.gcs) : 15;
const o2   = inp.on_oxygen === true || inp.on_oxygen === 'true';

if (!isNaN(rr)) {
  if      (rr <= 8)  { score += 3; notes.push('RR<=8: +3'); }
  else if (rr <= 11) { score += 1; notes.push('RR 9-11: +1'); }
  else if (rr <= 20) { notes.push('RR 12-20: +0'); }
  else if (rr <= 24) { score += 2; notes.push('RR 21-24: +2'); }
  else               { score += 3; notes.push('RR>=25: +3'); }
}
if (!isNaN(spo2)) {
  if      (spo2 <= 91) { score += 3; notes.push('SpO2<=91%: +3'); }
  else if (spo2 <= 93) { score += 2; notes.push('SpO2 92-93%: +2'); }
  else if (spo2 <= 95) { score += 1; notes.push('SpO2 94-95%: +1'); }
  else                 { notes.push('SpO2>=96%: +0'); }
}
if (o2) { score += 2; notes.push('On O2: +2'); }
if (!isNaN(sbp)) {
  if      (sbp <= 90)  { score += 3; notes.push('SBP<=90: +3'); }
  else if (sbp <= 100) { score += 2; notes.push('SBP 91-100: +2'); }
  else if (sbp <= 110) { score += 1; notes.push('SBP 101-110: +1'); }
  else if (sbp <= 219) { notes.push('SBP 111-219: +0'); }
  else                 { score += 3; notes.push('SBP>=220: +3'); }
}
if (!isNaN(hr)) {
  if      (hr <= 40)  { score += 3; notes.push('HR<=40: +3'); }
  else if (hr <= 50)  { score += 1; notes.push('HR 41-50: +1'); }
  else if (hr <= 90)  { notes.push('HR 51-90: +0'); }
  else if (hr <= 110) { score += 1; notes.push('HR 91-110: +1'); }
  else if (hr <= 130) { score += 2; notes.push('HR 111-130: +2'); }
  else                { score += 3; notes.push('HR>=131: +3'); }
}
if (!isNaN(temp)) {
  if      (temp <= 35.0) { score += 3; notes.push('Temp<=35: +3'); }
  else if (temp <= 36.0) { score += 1; notes.push('Temp 35.1-36: +1'); }
  else if (temp <= 38.0) { notes.push('Temp 36.1-38: +0'); }
  else if (temp <= 39.0) { score += 1; notes.push('Temp 38.1-39: +1'); }
  else                   { score += 2; notes.push('Temp>=39.1: +2'); }
}
if (!isNaN(gcs) && gcs < 15) { score += 3; notes.push('GCS<15: +3'); }

const risk =
  score >= 7 ? 'HIGH — immediate escalation required' :
  score >= 5 ? 'MEDIUM-HIGH — urgent review within 30 min' :
  score >= 3 ? 'MEDIUM — increased monitoring' :
               'LOW — routine monitoring';

return JSON.stringify({ NEWS2_score: score, risk_level: risk, score_breakdown: notes });

// HEART Score — Chest Pain Risk Stratification (Six et al. 2010)
const j   = $input.first().json;
const inp = (j.input && typeof j.input === 'object') ? j.input : j;

const history      = String(inp.history || '').toLowerCase();
const ecg          = String(inp.ecg     || '').toLowerCase();
const age          = parseFloat(inp.age);
const risk_factors = parseFloat(inp.risk_factors);
const troponin     = String(inp.troponin || '').toLowerCase();

const H = history.includes('highly')      ? 2 : history.includes('moderately') ? 1 : 0;
const E = ecg.includes('significant')     ? 2 : ecg.includes('non_specific') || ecg.includes('non-specific') ? 1 : 0;
const A = isNaN(age) ? 0 : age >= 65 ? 2 : age >= 45 ? 1 : 0;
const R = isNaN(risk_factors) ? 0 : risk_factors >= 3 ? 2 : risk_factors >= 1 ? 1 : 0;
const T = troponin.includes('gt') || troponin.includes('>3') ? 2 : troponin.includes('1_to') || troponin.includes('1-3') ? 1 : 0;

const score = H + E + A + R + T;

const mace_risk =
  score >= 7 ? 'HIGH (>50% 30d MACE) — immediate admit + invasive strategy' :
  score >= 4 ? 'MODERATE (12-17% MACE) — observe, serial troponins' :
               'LOW (<2% MACE) — consider early discharge';

const triage =
  score >= 7 ? 'URGENT minimum' :
  score >= 4 ? 'STANDARD minimum' :
               'NON-URGENT may be appropriate';

return JSON.stringify({
  heart_score: score,
  components: { H, E, A, R, T },
  mace_risk,
  triage_implication: triage,
  source: 'HEART Score — Six et al. 2010'
});

// Drug Interaction Checker — NIH RxNav API (no auth required)
const j   = $input.first().json;
const inp = (j.input && typeof j.input === 'object') ? j.input : j;
const raw = inp.drug_names || inp.query || inp.input || '';

const drugList = String(raw).split(',').map(d => d.trim()).filter(Boolean);

if (drugList.length < 2) {
  return JSON.stringify({
    note: 'Need at least 2 drug names for interaction check',
    received: drugList
  });
}

try {
  const cuiResults = await Promise.all(drugList.map(async (drug) => {
    const url = 'https://rxnav.nlm.nih.gov/REST/rxcui.json?name=' + encodeURIComponent(drug) + '&search=1';
    const res = await $http.request({ method: 'GET', url });
    const data = (res.body !== undefined) ? (typeof res.body === 'string' ? JSON.parse(res.body) : res.body) : res;
    const cui = data && data.idGroup && data.idGroup.rxnormId && data.idGroup.rxnormId[0] || null;
    return { drug, cui };
  }));

  const validCuis = cuiResults.filter(r => r.cui).map(r => r.cui);
  if (validCuis.length < 2) {
    return JSON.stringify({
      drugs: drugList,
      resolved: cuiResults,
      note: 'Could not resolve enough drugs to RxNorm CUI. Check spelling.',
      interactions: []
    });
  }

  const intUrl = 'https://rxnav.nlm.nih.gov/REST/interaction/list.json?rxcuis=' + validCuis.join('+');
  const intRes = await $http.request({ method: 'GET', url: intUrl });
  const intData = (intRes.body !== undefined) ? (typeof intRes.body === 'string' ? JSON.parse(intRes.body) : intRes.body) : intRes;

  const groups = (intData && intData.fullInteractionTypeGroup) || [];
  const interactions = [];
  for (const group of groups) {
    for (const type of (group.fullInteractionType || [])) {
      for (const pair of (type.interactionPair || [])) {
        interactions.push({
          drug1: pair.interactionConcept && pair.interactionConcept[0] && pair.interactionConcept[0].minConceptItem && pair.interactionConcept[0].minConceptItem.name || 'unknown',
          drug2: pair.interactionConcept && pair.interactionConcept[1] && pair.interactionConcept[1].minConceptItem && pair.interactionConcept[1].minConceptItem.name || 'unknown',
          severity: pair.severity || 'unknown',
          description: pair.description || ''
        });
      }
    }
  }

  return JSON.stringify({
    drugs: drugList,
    interaction_count: interactions.length,
    interactions,
    source: 'NLM RxNav API'
  });

} catch(e) {
  return JSON.stringify({ drugs: drugList, error: e.message, note: 'RxNav API unavailable' });
}

// ICD-10-CM Lookup — NLM Clinical Tables Search Service (public, no auth)
const j   = $input.first().json;
const inp = (j.input && typeof j.input === 'object') ? j.input : j;
const condition = String(inp.condition_name || inp.query || inp.input || '').trim().slice(0, 200);

if (!condition) {
  return JSON.stringify({ error: 'condition_name is required' });
}

try {
  const url = 'https://clinicaltables.nlm.nih.gov/api/icd10cm/v3/search?sf=code,name&terms=' + encodeURIComponent(condition) + '&maxList=3';
  const resp = await $http.request({ method: 'GET', url });
  const data = (resp.body !== undefined) ? (typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body) : resp;

  const total   = data[0] || 0;
  const display = data[3] || [];

  if (!display.length) {
    return JSON.stringify({ condition, icd10_code: null, note: 'No ICD-10 match found' });
  }

  const results = display.slice(0, 3).map(function(item) {
    return { code: item[0], name: item[1] };
  });

  return JSON.stringify({
    condition,
    icd10_code: results[0].code,
    icd10_description: results[0].name,
    alternatives: results.slice(1),
    total_matches: total,
    source: 'NLM Clinical Tables ICD-10-CM v3'
  });

} catch(e) {
  return JSON.stringify({ condition, icd10_code: null, error: e.message });
}

// CURB-65 — Community-Acquired Pneumonia Severity (Lim et al. BMJ 2003)
const j   = $input.first().json;
const inp = (j.input && typeof j.input === 'object') ? j.input : j;

const isTrue = (v) => v === true || v === 'true' || v === '1';

const C   = isTrue(inp.confusion) ? 1 : 0;
const U   = isTrue(inp.urea_gt7)  ? 1 : 0;
const R   = isTrue(inp.rr_gte30)  ? 1 : 0;
const B   = isTrue(inp.bp_low)    ? 1 : 0;
const Age = isTrue(inp.age_gte65) ? 1 : 0;

const score = C + U + R + B + Age;

const severity =
  score >= 3 ? 'SEVERE — 30d mortality 14-40% — hospital admission +/- ICU' :
  score === 2 ? 'MODERATE — 30d mortality ~9% — consider hospital admission' :
               'MILD — 30d mortality <3% — consider outpatient treatment';

const triage =
  score >= 3 ? 'URGENT minimum' :
  score === 2 ? 'STANDARD minimum' :
               'NON-URGENT may be appropriate';

return JSON.stringify({
  curb65_score: score,
  components: { C, U, R, B, Age65: Age },
  criteria_met: [
    C   ? 'Confusion'         : null,
    U   ? 'Urea >7 mmol/L'   : null,
    R   ? 'RR >=30/min'       : null,
    B   ? 'BP low'            : null,
    Age ? 'Age >=65'          : null
  ].filter(Boolean),
  severity_class: severity,
  triage_implication: triage,
  source: 'CURB-65 — Lim et al. BMJ 2003'
});

// RAG Pre-fetch — guaranteed retrieval before Diagnosis Agent
// Calls Ollama embeddings + Qdrant directly; no LLM tool call required.
const OLLAMA  = 'http://57.130.30.72:11434';
const QDRANT  = 'http://57.130.30.72:6333';
const MODEL   = 'nomic-embed-text:latest';

const features = $('🔬 Feature Extraction Agent').first().json.output || '';
let cc = '';
try {
  const parsed = JSON.parse(features);
  cc = (parsed.patient_summary && parsed.patient_summary.chief_complaint) || '';
} catch(e) {}
const clinicalInput = $('🏥 Patient Input').first().json.chatInput || '';
const query = cc || clinicalInput.substring(0, 300);

async function embed(text) {
  const r = await $http.request({
    method: 'POST',
    url: OLLAMA + '/api/embeddings',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: MODEL, prompt: text.slice(0, 1000) })
  });
  const d = typeof r.body === 'string' ? JSON.parse(r.body) : (r.body || r);
  return d.embedding || null;
}

async function search(collection, vector, topK) {
  const r = await $http.request({
    method: 'POST',
    url: QDRANT + '/collections/' + collection + '/points/search',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ vector, limit: topK, with_payload: true, score_threshold: 0.20 })
  });
  const d = typeof r.body === 'string' ? JSON.parse(r.body) : (r.body || r);
  return (d.result || []).map((p, i) => {
    const pl = p.payload || {};
    const text = pl.text_preview || pl.content || pl.presentation || JSON.stringify(pl);
    const title = pl.title || pl.case_code || pl.condition || '';
    return '[' + (i+1) + '] ' + (title ? title + '\n' : '') + text.slice(0, 500);
  });
}

let guidelinesText = 'No guidelines retrieved.';
let casesText = 'No similar cases retrieved.';
let embedOk = false;

try {
  const vec = await embed(query);
  if (vec && Array.isArray(vec) && vec.length > 0) {
    embedOk = true;
    const gChunks = await search('clinical_guidelines', vec, 5);
    const cChunks = await search('clinical_cases', vec, 3);
    if (gChunks.length > 0) guidelinesText = gChunks.join('\n\n---\n\n');
    if (cChunks.length > 0) casesText = cChunks.join('\n\n---\n\n');
  }
} catch(e) {
  guidelinesText = 'RAG unavailable: ' + e.message;
}

return [{
  json: {
    rag_query:              query,
    embed_ok:               embedOk,
    guidelines_retrieved:   guidelinesText,
    cases_retrieved:        casesText,
    extractor_output:       features
  }
}];
